var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......아무리 그래도 이번엔 장난이 좀 과했어, 알렉스 부전대장.","JPN":"……いくら何でも今回はやり過ぎだ、アレックス副戦隊長。","ENG":"No matter what you say, you went overboard this time, Deputy Commander Alex.","TWN":"……妳這次玩笑開的有點過分了，雅蕾克絲副隊長。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"얌전히 식사만 하겠다고 해서 참석을 허락해 줬는데 이렇게 큰 사고를 치면 어떡하나?","JPN":"大人しく食事をするだけだと言うから許したものを、こんなことをしてどうするつもりだ？","ENG":"You said you just wanted to eat. I would never have let you come if I knew you'd cause so much trouble.","TWN":"妳說妳只是吃個飯就回來，所以我才允許妳參加，但妳卻闖了那麼大的禍！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"하지만 그림자 세계 안은 너무 지루한걸. 애들 먹을 것도 없고.","JPN":"でも、シャドウ世界はつまらないもの。この子たちが食べる物もないし。","ENG":"But it's too boring to stay in the Shadow World all the time. The kids wanted some food, too.","TWN":"可是暗影世界太無聊了，也沒有東西可以吃。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"물론 이젠 음식을 먹지 않아도 되는 몸이 되긴 했지만......","JPN":"もちろん、今は何も食べなくても問題はないけど……","ENG":"Although we don't need food to sustain ourselves anymore.","TWN":"當然現在的身體，已經不用吃了……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"그렇다고 나 혼자만 요즘 애들이랑 노는 건 너무 의리가 없잖아?","JPN":"だからって私だけが若い子たちと遊ぶのも悪いじゃない？","ENG":"Also, I didn't feel right about having fun out here without them.","TWN":"況且我自己去玩也顯得太沒義氣。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"겸사겸사 안에서 지루해하는 애들을 위해 작은 이벤트를 만들어 준 거야.","JPN":"だから、この子たちのために些細なイベントを開いただけなのよ。","ENG":"So I did it for the kids in the Shadow World, as a small entertainment.","TWN":"所以順便為無聊的孩子們準備了小小的驚喜。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"아무리 그렇다고 해도 관리자님을 곤란하게 만든 건 잘못된 행동이다, 부전대장.","JPN":"いくらそうだとしても管理者様を困らせるのは間違っていると思わないか、副戦隊長。","ENG":"Even so, you put the Administrator in a very difficult situation, Deputy Commander.","TWN":"即使如此，妳讓管理者大人這麼為難就是有錯，副隊長。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"사과하도록.","JPN":"謝罪をするように。","ENG":"You should apologize.","TWN":"道歉吧。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"후훗. 류드밀라는 너무 딱딱하다니까.","JPN":"ふふっ。リュドミラちゃんは頭が固いんだから。","ENG":"Heh. Lyudmila, you're so stiff.","TWN":"哼，盧德米拉真是太死板了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"그래도 사과를 하라니 해야지. 이번엔 미안했어, 자기야.","JPN":"でも謝罪しろっていうならしないとね。今回はやり過ぎたわ、ごめんなさい。","ENG":"But if you want me to apologize, then I will. I'm sorry, honey.","TWN":"不過我還是會道歉的，這次真的很對不起，親愛的。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"용서해 줄 거지? 나쁜 뜻은 없었어.","JPN":"許してくれるわよね？　悪意はなかったの。","ENG":"You'll forgive me, right? I didn't mean anything bad.","TWN":"你會原諒我吧？我沒有什麼惡意。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"끄응......","JPN":"ううっ……","ENG":"*Groan*","TWN":"呃……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"죄송합니다, 관리자님.","JPN":"管理者様、申し訳ありません。","ENG":"I'm sorry, Administrator.","TWN":"對不起，管理者大人。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"제가 전대원 관리에 좀 더 신경을 썼어야 했는데......","JPN":"私が戦隊員の管理にもう少し気を遣うべきでした。","ENG":"I should have paid more attention to the others.","TWN":"我應該好好管一管隊員的……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아닐세. 애초에 임대료 좀 아껴보자고 자네의 그림자 세계 안에 파티용 산장을 만들어 달라고 했던 것부터 실수였던 것 같아.","JPN":"いや、そもそも賃貸料を減らそうと君のシャドウ世界に\\nパーティー用の山荘を作ったことが間違いだったのだ。","ENG":"No, I shouldn't have asked you to create the cabin inside your Shadow World just to save a small rental fee. It's my fault.","TWN":"沒事。一開始就不該為了省下租金，讓妳在妳的暗影世界建出一個舉辦派對的山莊。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그보다 성야의 살인마라니 대체 그건 뭔가? 테라브레인은 또 어떻게 해킹한 거고.","JPN":"それより、聖夜の殺人鬼とは一体何なんだ？\\nどうやってテラブレインにハッキングを……","ENG":"Anyway, what is this Killer of the Holy Night? And how did you hack into the Terrabrain?","TWN":"話說，耶誕的嫌疑犯到底是什麼？又是怎麼入侵特拉大腦的？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"파티장에서 자네와 얘기한 뒤로 연결이 끊어져서 많이 당황했었네.","JPN":"パーティーで君と話してから接続が途切れて驚いたぞ。","ENG":"I was really confused when I got disconnected after talking to you at the party.","TWN":"在山莊和妳對話後就突然斷線了，讓我很驚慌啊。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"아, 성야의 살인마라는 건 구 관리국 시절에 하던 놀이야.","JPN":"ああ、聖夜の殺人鬼っていうのは旧管理局時代にやってた遊びよ。","ENG":"Ah, the Killer of the Holy Night is a game that we played during the Old Administration.","TWN":"啊，耶誕的嫌疑犯是在舊管理局的時候玩過的。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"신병이 오면 담력시험 삼아 놀려 주는 데 써먹는 설정이었지. 그때는 그림자형 침식체였지만.","JPN":"新入りが入った時の肝試しで使っていた設定なの。あの時はシャドウ型侵食体だったけど。","ENG":"To haze recruits, to be precise. We used Shadows back then.","TWN":"每當有新兵進來，都用會這個設定來唬他們，順便練練他們的膽量，不過那時候是叫暗影侵蝕體。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"류드밀라도 된통 당했다지, 아마?","JPN":"リュドミラちゃんも、かなりやられたものね？","ENG":"Lyudmila, you were hazed too, weren't you?","TWN":"盧德米拉當時也被擺了一道吧？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"정말 사람들이 그림자에게 당한 줄 알고 펑펑 울면서......","JPN":"本当にみんながシャドウにやられたと思ってわんわん泣いちゃって……","ENG":"You thought the Shadows really got the people, so you cried—","TWN":"以為人們真的被暗影殺了，然後大哭大鬧的……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그, 그때 이야기는 하지 말도록!","JPN":"あ、あの時の話はするな！","ENG":"I-I don't want to talk about it!","TWN":"那、那時候的事情還是不要提了！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"후훗. 그리고 테라브레인은...... 파티 중에 우리 부사장님의 보안암호를 우연히 엿들었거든.","JPN":"ふふっ、とにかくテラブレインの方は……\\nパーティー中に副社長のセキュリティパスワードを偶然耳にしてね。","ENG":"Hah hah. As for the Terrabrain, I heard someone mentioning the Vice President's security password during the party.","TWN":"嘿嘿，還有特拉大腦……參加派對的時候我偶然間聽到了副總的安全金鑰。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"그걸 입력하니까 간단히 탈취되더라고.","JPN":"それを入力したら簡単に奪取できたの。","ENG":"I entered it, and I was in control of the system.","TWN":"輸入那個密碼之後，很容易就到手了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"덕분에 설정 설명용 캐릭터로 잘 써먹었어.","JPN":"おかげで設定説明用のキャラクターに使わせてもらったわ。","ENG":"Your robot was really useful for setting up the mood.","TWN":"多虧了那個，我倒是創造出了一個不錯的角色。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"그러고 보니 그 암호 대체 무슨 뜻이야?","JPN":"そういえば、あのパスワードってどういう意味？","ENG":"What does that password mean, anyway?","TWN":"話說，那個密碼到底是什麼意思？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"LSY......","JPN":"KZN……","ENG":"LSY—","TWN":"LSY……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"시, 시끄럽군요! 아무 의미도 없습니다! 없어요!!","JPN":"う、うるさいですね！　何の意味もありません！　とにかくありません！！","ENG":"D-don't say anymore! It doesn't mean anything—I mean it!","TWN":"閉、閉嘴！沒有什麼意思！沒有！！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"남의 암호를 가지고 이러쿵저러쿵 떠들지 마시죠! 개인 정보입니다!","JPN":"これ以上、その件については他言無用です！　個人情報ですので！","ENG":"You shouldn't talk about other people's passwords. That's private information!","TWN":"不要拿別人的密碼說三道四了！那可是隱私！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"흐음. 그렇지만 궁금한걸.","JPN":"ふーん、でも……気になるわね。","ENG":"Hm, but I'm curious.","TWN":"唔，不過我很好奇。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"그래, 뭔가 맛있는 걸 먹으면 궁금증이 사라지려나?","JPN":"何か美味しいものでも食べれば、気が紛れるかしら？","ENG":"Oh, maybe I won't be curious anymore if I eat something delicious.","TWN":"吃好吃的東西是不是就能解決這個好奇心了？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아니, 정말......!","JPN":"まったく……！","ENG":"What? You can't—","TWN":"妳真是……！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 정도면 나쁘지 않은 거래로군.","JPN":"それなら悪くない取引だな。","ENG":"That's a reasonable trade-off.","TWN":"確實是個不錯的交易。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우리 부사장의 명예를 위해 내가 맛있는 식사로 알렉스 양의 입을 막도록 하지.","JPN":"副社長の名誉のために私がおいしい食事でアレックスを口封じするとしよう。","ENG":"Vice President, let me treat Alex to a delicious dinner and protect your honor.","TWN":"為了我們副總的名聲，我願意用一頓美味大餐堵住雅蕾克絲小姐的嘴。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"정말이야?","JPN":"本当に？","ENG":"For real?!","TWN":"真的嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"물론일세.","JPN":"もちろんだ。","ENG":"Yes.","TWN":"當然。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"원래 식사를 하거나 잠을 잔다는 건 인간으로서의 정체성을 유지하는데 큰 도움이 되지.","JPN":"食事をしたり睡眠を取るということは、\\n人間としてのアイデンティティを維持するのにとても大切なことだからな。","ENG":"Eating and sleeping can greatly help you maintain your human identity.","TWN":"原本吃飯和睡覺，有助於維持人類的本質。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네들의 처지를 생각하면 평소에 신경을 더 써 주지 못한 게 오히려 미안할 정도야.","JPN":"君たちの立場を考えると、日頃からもっと気にかけてやればよかったと反省するくらいだ。","ENG":"Considering your situation, I feel sorry that I couldn't pay more attention to you.","TWN":"想想你們的處境，我平時應該多費心的，這著實讓我愧疚。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러니 가끔은 회식도 나쁘지 않겠지. 스트레스가 쌓이지 않게 말이야.","JPN":"だから、たまには会食もいいだろう。ストレス発散にな。","ENG":"So, yes, I think occasional company outings are not a bad idea. They can definitely help relieve stress.","TWN":"所以偶爾聚餐也挺好的，至少能緩解壓力。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"특별히 먹고 싶은 음식이라도 있나?","JPN":"何か食べたいものはあるか？","ENG":"Is there anything you want to eat?","TWN":"有沒有什麼特別想吃的東西？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"아, 관리자님. 그렇다면 역시 다 함께 둘러앉아 고향의 맛을 담은 전통 수프를......","JPN":"ああ、管理者様。でしたらみんなでテーブルを囲んで、故郷の味の伝統スープを……","ENG":"Ah, Administrator, then I'd love us to sit together and enjoy some traditional soup—","TWN":"管理者大人，我認為最好可以圍在一起品嘗具有家鄉味的傳統濃湯……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"고기가 좋겠네. 저번에 보니까 철판에 구워 먹던데 맛있어 보이더라.","JPN":"お肉がいいわ。鉄板の上で焼いてたのが、おいしそうだったの。","ENG":"Meat! I saw you eating grilled meat last time. It looked delicious.","TWN":"烤肉吧，上次看到有人用鐵板烤肉來吃，看起來很美味。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"훌륭한 선택입니다, 부전대장님.","JPN":"素晴らしい選択です、副戦隊長殿。","ENG":"Excellent choice, Deputy Commander.","TWN":"真是好提議，副隊長大人。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"조각상 연기를 하면서 직원들 이야기를 엿들었는데 회식은 역시 고기라더군요.","JPN":"彫刻像の演技をしている最中、耳にしたのですが。会食はやはりお肉だそうです。","ENG":"While acting as the sculpture, I eavesdropped on the employees. They also liked to eat meat for company outings.","TWN":"我扮成雕像偷聽員工們說話的時候，聽到她們說聚餐就該吃烤肉。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"좋아, 그럼 어서 가지!","JPN":"よしっ、じゃあ食べに行こう。","ENG":"Alright, then let's go!","TWN":"好，那我們走吧！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"계산은 부사장이 법인카드로 할 테니까!","JPN":"会計は副社長が法人カードでしてくれるさ！","ENG":"The Vice President has the company credit card!","TWN":"結帳就用副總的商務卡吧！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아니, 잠깐! 잠깐만요!!","JPN":"いや、ちょっと！　お待ちください！","ENG":"What? Wait, wait!","TWN":"喂，等等！等等！！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_04"},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사장님!!","JPN":"社長！！","ENG":"Boss!","TWN":"老闆！！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"작전기록 녹음. 알렉스를 비롯해 전대원들도 모두 들떠 있다.","JPN":"作戦記録を録音。アレックスをはじめ、戦隊員たちも喜んでいる。","ENG":"Operation log. Everyone including Alex is excited.","TWN":"作戰記錄錄音。包括雅蕾克絲在內的所有隊員都顯得非常興奮。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L23_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"개인적인 소견으로는 새로운 전우들을 만나서 기쁜 모양이다.","JPN":"個人的な意見としては、新しい戦友に会えて嬉しいようだ。","ENG":"In my personal opinion, I think they're happy to meet their new comrades.","TWN":"我個人認為，應該是新的戰友讓她們很高興。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"관리자님께 폐를 끼치긴 했지만, 복귀 당시보다 상태들이 많이 호전되어 다행이야.","JPN":"管理者様に迷惑をかけてしまったが、復帰当時よりは状態が良くなって安心した。","ENG":"We put the Administrator in trouble, but I'm glad that the others get better than they were when we first returned.","TWN":"雖然給管理者大人帶來了麻煩，但所幸的是大家的狀態比回歸時好轉了許多。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하지만 아무리 그렇다고 해도 이 공간은 당장 폐쇄를......","JPN":"しかし、この空間は今すぐ閉鎖を……","ENG":"But regardless, this space needs to be shut down right awa—","TWN":"即便如此，這個空間應該立即關閉……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"음?","JPN":"ん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"사, 산장...... 산장은 어디 있는 거죠?","JPN":"さ、山荘は……どこにあるんですか？","ENG":"Th-the cabin... Where's the cabin?","TWN":"山、山莊……山莊在哪裡？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"이제 틀렸어요. 코핀 컴퍼니 회사 분들이 이런 데서 파티를 열 리가 없었는데......","JPN":"もうダメです。\\nコフィンカンパニーの皆さんがこんなところでパーティーを開くはずがありません……","ENG":"We missed the mark. There's no way the Coffin Company would throw a party in a place like this.","TWN":"不對吧，科芬公司的員工們怎麼可能在這裡開派對……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"크흑! 올해 마지막으로 공짜 밥을 먹을 수 있는 기회가 이렇게 틀어지다니!","JPN":"はぁ、今年最後のタダ飯を食べるチャンスを逃すなんて！","ENG":"*Sniffle!* We lost our last chance to enjoy free meals this year!","TWN":"咳！我就這麼錯過了今年最後一次可以免費吃飯的機會！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"포기하세요, 히로세 씨. 처음부터 저희 인생에 성공이란 두 글자는 없었던 거예요.","JPN":"廣瀬さん、諦めましょう。\\nヒミコたちの人生に成功という二文字は存在しないのです。","ENG":"Just give up, Ms. Hirose. We're not meant to succeed at anything in life.","TWN":"放棄吧，廣瀨。我們人生裡就從來沒有過成功兩個字。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"내놓는 기획서마다 반려 당하는 기획자 같은 인생이죠......","JPN":"すべての企画書が却下されるような人生なんですよ……","ENG":"No. We're like game developers whose ideas always get rejected.","TWN":"就像上交的企劃書都被反駁的企劃者人生一樣……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"조난자 2인 발견. 상태가 심각해 보이므로......","JPN":"遭難者2名発見。深刻な状態を察知……","ENG":"I've found two stranded individuals. They appear to be in serious condition—","TWN":"發現兩名遇難者，狀態看起來很差……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"후, 후후......","JPN":"フ、フフ……","ENG":"Hah, hah hah...","TWN":"呵，呵呵……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"고향을 떠나 멀고먼 눈 덮인 산까지 왔건만 고독을 나눌 친구 한 명 얻지 못하다니......","JPN":"故郷を離れて遠い雪山に来たが、孤独を分かち合う友一人すらできぬとはな……","ENG":"I left my domicile and came all the way to this snowy mountain in hopes of finding one true friend to share my loneliness with.","TWN":"離開家鄉後來到了遙遠的雪山，沒想到居然沒能找到一個可以交心的朋友……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"하지만 부평초처럼 바람과 함께 흘러가는 그것이 인생! 오오, 그것이 젊음!","JPN":"だが、浮き草のように風とともに流れていくのが人生！\\nああ、それが若さというもの！","ENG":"And instead of a friend, I've found a snowfield stretching away before my eyes, just like my life—my youth!","TWN":"人生如浮萍，四處隨風飄蕩！噢，那就是青春啊！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"이 몸, 린 시엔! 한 철 지나갈 뿐인 추위에 굴복하지 않는 풍운아 아니겠는가!","JPN":"このリン・シエン！　季節外れの寒さに屈することない風雲よ、そうだろう？","ENG":"But I'm Lin Xien! I refuse to succumb to this bitter cold, something that only lasts for one season!","TWN":"我，林·西恩！一個絕不屈服於轉眼即逝的寒冷的風雲人物！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"......흐어어, 추워.","JPN":"……うぅ、寒い。","ENG":"Aww... So cold...","TWN":"……呃呃，好冷。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"정정한다. 조난자는 3인.","JPN":"訂正する。遭難者3名。","ENG":"I correct: three stranded individuals.","TWN":"在此更正，遇難者為三人。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"전원 상태가 심각해 보이므로 구조하겠다.","JPN":"全員、深刻な状態と見受けられる。今すぐ救助する。","ENG":"They all appear to be in serious condition. I'll rescue them.","TWN":"全員狀態皆差，需要進行救助。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이상.","JPN":"以上。","ENG":"Over and out.","TWN":"完畢。"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};